function BedIcon({type,size=28}){
  const s=size;
  const h=Math.round(s*0.6);
  // Couleurs
  const frame="#8B6434";
  const mat="#e8d8b0";
  const pil="#fff";
  const pilB="#d4c090";

  if(type==="Suite"){
    return(
      <svg width={s+8} height={h} viewBox={"0 0 "+(s+8)+" "+h} style={{display:"block"}}>
        {/* Grand lit double — cadre */}
        <rect x="2" y={h*0.35} width={s+4} height={h*0.55} rx="3" fill={mat} stroke={frame} strokeWidth="1.5"/>
        {/* Tête de lit */}
        <rect x="2" y={h*0.1} width="8" height={h*0.32} rx="2" fill={frame}/>
        {/* Matelas */}
        <rect x="12" y={h*0.38} width={s-10} height={h*0.48} rx="2" fill="#f5efe0"/>
        {/* 1 grand oreiller */}
        <rect x="14" y={h*0.42} width={s-20} height={h*0.22} rx="2" fill={pil} stroke={pilB} strokeWidth="1"/>
        {/* Étoile suite */}
        <text x={s-2} y={h*0.28} fontSize="9" fill="#c9952a">✨</text>
      </svg>
    );
  }
  if(type==="Double"){
    return(
      <svg width={s} height={h} viewBox={"0 0 "+s+" "+h} style={{display:"block"}}>
        {/* Cadre lit */}
        <rect x="2" y={h*0.35} width={s-4} height={h*0.55} rx="3" fill={mat} stroke={frame} strokeWidth="1.5"/>
        {/* Tête de lit */}
        <rect x="2" y={h*0.1} width="7" height={h*0.3} rx="2" fill={frame}/>
        {/* Matelas */}
        <rect x="11" y={h*0.38} width={s-15} height={h*0.48} rx="2" fill="#f5efe0"/>
        {/* 1 oreiller large (lit double = 1 grand oreiller) */}
        <rect x="13" y={h*0.42} width={s-22} height={h*0.2} rx="2" fill={pil} stroke={pilB} strokeWidth="1"/>
      </svg>
    );
  }
  if(type==="Twin"){
    const w2=Math.round((s-10)/2);
    return(
      <svg width={s+4} height={h} viewBox={"0 0 "+(s+4)+" "+h} style={{display:"block"}}>
        {/* Lit gauche */}
        <rect x="1" y={h*0.35} width={w2} height={h*0.55} rx="2" fill={mat} stroke={frame} strokeWidth="1.2"/>
        <rect x="1" y={h*0.12} width="5" height={h*0.27} rx="1.5" fill={frame}/>
        <rect x="7" y={h*0.39} width={w2-8} height={h*0.45} rx="1.5" fill="#f5efe0"/>
        <rect x="8" y={h*0.42} width={w2-12} height={h*0.18} rx="1.5" fill={pil} stroke={pilB} strokeWidth="1"/>
        {/* Séparateur */}
        <line x1={w2+4} y1={h*0.3} x2={w2+4} y2={h*0.95} stroke="#c9b080" strokeWidth="1" strokeDasharray="2,2"/>
        {/* Lit droit */}
        <rect x={w2+7} y={h*0.35} width={w2} height={h*0.55} rx="2" fill={mat} stroke={frame} strokeWidth="1.2"/>
        <rect x={w2+7} y={h*0.12} width="5" height={h*0.27} rx="1.5" fill={frame}/>
        <rect x={w2+13} y={h*0.39} width={w2-8} height={h*0.45} rx="1.5" fill="#f5efe0"/>
        <rect x={w2+14} y={h*0.42} width={w2-12} height={h*0.18} rx="1.5" fill={pil} stroke={pilB} strokeWidth="1"/>
      </svg>
    );
  }
  if(type==="Triple"){
    const w3=Math.round((s-8)/3);
    return(
      <svg width={s+6} height={h} viewBox={"0 0 "+(s+6)+" "+h} style={{display:"block"}}>
        {[0,1,2].map(i=>(
          <g key={i}>
            <rect x={i*(w3+4)+1} y={h*0.35} width={w3} height={h*0.55} rx="2" fill={mat} stroke={frame} strokeWidth="1"/>
            <rect x={i*(w3+4)+1} y={h*0.15} width="4" height={h*0.24} rx="1.5" fill={frame}/>
            <rect x={i*(w3+4)+6} y={h*0.39} width={w3-7} height={h*0.45} rx="1.5" fill="#f5efe0"/>
            <rect x={i*(w3+4)+7} y={h*0.43} width={w3-10} height={h*0.16} rx="1.5" fill={pil} stroke={pilB} strokeWidth="1"/>
          </g>
        ))}
      </svg>
    );
  }
  // Single (1/2 Lit)
  return(
    <svg width={Math.round(s*0.55)} height={h} viewBox={"0 0 "+Math.round(s*0.55)+" "+h} style={{display:"block"}}>
      <rect x="2" y={h*0.35} width={Math.round(s*0.55)-4} height={h*0.55} rx="3" fill={mat} stroke={frame} strokeWidth="1.5"/>
      <rect x="2" y={h*0.1} width="7" height={h*0.3} rx="2" fill={frame}/>
      <rect x="11" y={h*0.38} width={Math.round(s*0.55)-15} height={h*0.48} rx="2" fill="#f5efe0"/>
      <rect x="13" y={h*0.42} width={Math.round(s*0.55)-20} height={h*0.2} rx="2" fill={pil} stroke={pilB} strokeWidth="1"/>
    </svg>
  );
}
